tool_input.code:
import numpy as np

# Let me look at the 8-shape structure and internal colors for each example
for i, s in enumerate(train_samples):
    inp = np.array(s['input'])
    out = np.array(s['output'])
    H, W = inp.shape

    print(f"\n=== Example {i} ===")
    print(f"Size: {H}x{W}")

    # Find 8-connected components of 8s
    eights = set(zip(*np.where(inp == 8)))
    print(f"8-positions: {sorted([(int(r),int(c)) for r,c in eights])}")

    # Find all non-0 non-8 cells
    non_zero = {}
    for r in range(H):
        for c in range(W):
            if inp[r][c] != 0 and inp[r][c] != 8:
                non_zero[(r,c)] = int(inp[r][c])

    # Separate "legend" cells (near 8s) from "pattern" cells (far from 8s)
    # Start with 8s, expand by 1 step, and include connected colored cells
    legend = set()
    to_check = list(eights)
    visited = set(eights)
    while to_check:
        r, c = to_check.pop()
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if (nr,nc) not in visited and (nr,nc) in non_zero:
                legend.add((nr,nc))
                visited.add((nr,nc))
                to_check.append((nr,nc))

    print(f"Legend cells (near 8s): {sorted([(int(r),int(c),non_zero[(r,c)]) for r,c in legend])}")

    pattern = {k:v for k,v in non_zero.items() if k not in legend}
    print(f"Pattern cells (far from 8s): {sorted([(int(r),int(c),v) for (r,c),v in pattern.items()])}")

    # Output colors
    out_cells = {}
    for r in range(H):
        for c in range(W):
            if out[r][c] != 0:
                out_cells[(r,c)] = int(out[r][c])
    print(f"Output cells: {sorted([(int(r),int(c),v) for (r,c),v in out_cells.items()])}")

