import numpy as np
from collections import deque

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape
    output = np.zeros((H, W), dtype=int)

    # Find 8-connected components of 8-cells
    eights = set()
    for r in range(H):
        for c in range(W):
            if grid[r,c] == 8:
                eights.add((r,c))

    def find_8conn_components(cells):
        remaining = set(cells)
        components = []
        while remaining:
            start = remaining.pop()
            comp = {start}
            queue = deque([start])
            while queue:
                r, c = queue.popleft()
                for dr in [-1,0,1]:
                    for dc in [-1,0,1]:
                        if dr == 0 and dc == 0: continue
                        nr, nc = r+dr, c+dc
                        if (nr,nc) in remaining:
                            remaining.remove((nr,nc))
                            comp.add((nr,nc))
                            queue.append((nr,nc))
            components.append(comp)
        return components

    eight_comps = find_8conn_components(eights)

    # For each 8-component, find legend chain: A→B→8
    # B is a non-8, non-0 cell that is 4-adjacent to some 8 in the component
    # A is a non-8, non-0 cell that is 4-adjacent to B and NOT adjacent to any 8
    legends = []  # list of (A_pos, A_color, B_pos, B_color, eight_comp)
    legend_cells = set()

    for comp in eight_comps:
        # Find B-cells: non-8, non-0 cells 4-adjacent to some 8 in comp
        b_candidates = {}
        for r, c in comp:
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < H and 0 <= nc < W and (nr,nc) not in eights:
                    v = int(grid[nr,nc])
                    if v != 0 and v != 8:
                        b_candidates[(nr,nc)] = v

        # For each B, find A: non-8, non-0 cell 4-adjacent to B, NOT adjacent to any 8
        for b_pos, b_color in b_candidates.items():
            br, bc = b_pos
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = br+dr, bc+dc
                if 0 <= nr < H and 0 <= nc < W and (nr,nc) not in eights:
                    v = int(grid[nr,nc])
                    if v != 0 and v != 8 and v != b_color and (nr,nc) != b_pos:
                        # Check that this cell is NOT 4-adjacent to any 8 in this comp
                        adj_to_8 = False
                        for dr2, dc2 in [(-1,0),(1,0),(0,-1),(0,1)]:
                            if (nr+dr2, nc+dc2) in comp:
                                adj_to_8 = True
                                break
                        if not adj_to_8:
                            legends.append(((nr,nc), v, b_pos, b_color, comp))
                            legend_cells.add((nr,nc))
                            legend_cells.add(b_pos)

    # Build color mapping: A_color → B_color
    color_map = {}
    for a_pos, a_color, b_pos, b_color, comp in legends:
        color_map[a_color] = b_color

    # Identify pattern cells (non-8, non-0, not in legend_cells)
    pattern_cells = {}
    for r in range(H):
        for c in range(W):
            v = int(grid[r,c])
            if v != 0 and v != 8 and (r,c) not in legend_cells:
                pattern_cells[(r,c)] = v

    # Simple approach: just color swap at same position
    for (r,c), v in pattern_cells.items():
        new_color = color_map.get(v, v)  # swap if mapping exists, else keep
        output[r,c] = new_color

    return output.tolist()

# Test on training examples
for idx, s in enumerate(train_samples):
    out = solve(s['input'])
    expected = s['output']
    match = (np.array(out) == np.array(expected)).all()
    if not match:
        diff_count = (np.array(out) != np.array(expected)).sum()
        print(f"Example {idx}: MISMATCH ({diff_count} cells differ)")
    else:
        print(f"Example {idx}: MATCH ✓")

