from collections import deque

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape
    output = np.zeros((H, W), dtype=int)

    eights = set()
    for r in range(H):
        for c in range(W):
            if grid[r,c] == 8:
                eights.add((r,c))

    # Find chains: A→B→8 where B is 8-adjacent to 8, A is 4-adjacent to B
    legend_cells = set()
    color_transforms = {}

    # Find B candidates: non-8, non-0 cells that are 8-adjacent (Chebyshev dist 1) to some 8
    b_candidates = set()
    for r, c in eights:
        for dr in [-1,0,1]:
            for dc in [-1,0,1]:
                if dr == 0 and dc == 0: continue
                nr, nc = r+dr, c+dc
                if 0 <= nr < H and 0 <= nc < W and (nr,nc) not in eights:
                    v = int(grid[nr,nc])
                    if v != 0:
                        b_candidates.add((nr,nc))

    # Find A candidates: non-8, non-0, 4-adj to B, NOT in b_candidates
    chains = []
    for b_pos in b_candidates:
        b_color = int(grid[b_pos[0], b_pos[1]])
        br, bc = b_pos
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = br+dr, bc+dc
            if 0 <= nr < H and 0 <= nc < W and (nr,nc) not in eights:
                v = int(grid[nr,nc])
                if v != 0 and v != b_color and (nr,nc) not in b_candidates:
                    chains.append(((nr,nc), v, b_pos, b_color))

    # Determine if the 8-structure is a line or diamond/other
    # For each chain, find the 8-cells adjacent to B
    for a_pos, a_color, b_pos, b_color in chains:
        legend_cells.add(a_pos)
        legend_cells.add(b_pos)

        # Find 8-cells 8-adjacent to B
        br, bc = b_pos
        adj_eights = set()
        for dr in [-1,0,1]:
            for dc in [-1,0,1]:
                if dr == 0 and dc == 0: continue
                nr, nc = br+dr, bc+dc
                if (nr,nc) in eights:
                    adj_eights.add((nr,nc))

        # Flood-fill from adj_eights through all 8-cells using 8-connectivity
        structure = set(adj_eights)
        queue = deque(list(adj_eights))
        while queue:
            r, c = queue.popleft()
            for dr in [-1,0,1]:
                for dc in [-1,0,1]:
                    if dr == 0 and dc == 0: continue
                    nr, nc = r+dr, c+dc
                    if (nr,nc) in eights and (nr,nc) not in structure:
                        structure.add((nr,nc))
                        queue.append((nr,nc))

        # Check if structure + A + B form a line
        all_chain = list(structure) + [a_pos, b_pos]
        rows = set(r for r,c in all_chain)
        cols = set(c for r,c in all_chain)

        is_line = (len(rows) == 1) or (len(cols) == 1)

        if is_line and len(structure) >= 2:
            # Stamp extension
            offsets = [(cell[0]-a_pos[0], cell[1]-a_pos[1]) for cell in all_chain]
            color_transforms[a_color] = (b_color, 'stamp', offsets)
        elif is_line and len(structure) == 1:
            # Single 8-cell line: just color swap
            color_transforms[a_color] = (b_color, 'swap', None)
        else:
            # 3-neighbor spread
            # Excluded direction = opposite of A→B
            a2b_r = b_pos[0] - a_pos[0]
            a2b_c = b_pos[1] - a_pos[1]
            # Opposite direction
            if abs(a2b_r) >= abs(a2b_c):
                excluded = (-1 if a2b_r > 0 else 1, 0)
            else:
                excluded = (0, -1 if a2b_c > 0 else 1)
            color_transforms[a_color] = (b_color, 'spread', excluded)

    # Also mark inner cross cells as legends (for diamond structures)
    # Find non-8, non-0 cells that are ALSO b_candidates and have a chain partner
    # (these are already handled above as A or B cells)

    # Pattern cells
    for r in range(H):
        for c in range(W):
            v = int(grid[r,c])
            if v != 0 and v != 8 and (r,c) not in legend_cells:
                if v in color_transforms:
                    b_color, method, info = color_transforms[v]
                    if method == 'stamp':
                        for dr, dc in info:
                            nr, nc = r + dr, c + dc
                            if 0 <= nr < H and 0 <= nc < W:
                                output[nr, nc] = b_color
                    elif method == 'spread':
                        excluded = info
                        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
