                                nr, nc = r + dr, c + dc
                                if 0 <= nr < H and 0 <= nc < W:
                                    output[nr, nc] = b_color
                    else:  # swap
                        output[r, c] = b_color
                else:
                    output[r, c] = v

    return output.tolist()

# Test
for idx, s in enumerate(train_samples):
