        for d in diffs[:3]:
            r, c = int(d[0]), int(d[1])
            print(f"  ({r},{c}): got={out_arr[r,c]}, expected={exp_arr[r,c]}")
    else:
        print(f"Example {idx}: MATCH ✓")

