import numpy as np
from collections import deque

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape
    output = np.zeros((H, W), dtype=int)

    # Find all 8-cells
    eights = set()
    for r in range(H):
        for c in range(W):
            if grid[r,c] == 8:
                eights.add((r,c))

    # Find 8-structures via flood fill (8-connected)
    visited_8 = set()
    structures = {}  # maps each 8-cell to its structure (set of cells)

    for r, c in eights:
        if (r,c) in visited_8:
            continue
        struct = set()
        q = deque([(r,c)])
        while q:
            cr, cc = q.popleft()
            if (cr,cc) in visited_8:
                continue
            visited_8.add((cr,cc))
            struct.add((cr,cc))
            for dr in [-1,0,1]:
                for dc in [-1,0,1]:
                    if dr == 0 and dc == 0: continue
                    nr, nc = cr+dr, cc+dc
                    if (nr,nc) in eights and (nr,nc) not in visited_8:
                        q.append((nr,nc))
        for cell in struct:
            structures[cell] = struct

    # Find chains via ray-based detection
    chains = []
    seen_chains = set()

    for r, c in eights:
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            while 0 <= nr < H and 0 <= nc < W:
                v = int(grid[nr, nc])
                if v == 8: break
                if v != 0:
                    b_pos = (nr, nc)
                    b_color = v
