import numpy as np
from collections import deque

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape
    output = np.zeros((H, W), dtype=int)

    # Find all 8-cells
    eights = set()
    for r in range(H):
        for c in range(W):
            if grid[r,c] == 8:
                eights.add((r,c))

    # Find 8-structures via flood fill (8-connected)
    visited_8 = set()
    structures = {}  # maps each 8-cell to its structure (set of cells)

    for r, c in eights:
        if (r,c) in visited_8:
            continue
        struct = set()
        q = deque([(r,c)])
        while q:
            cr, cc = q.popleft()
            if (cr,cc) in visited_8:
                continue
            visited_8.add((cr,cc))
            struct.add((cr,cc))
            for dr in [-1,0,1]:
                for dc in [-1,0,1]:
                    if dr == 0 and dc == 0: continue
                    nr, nc = cr+dr, cc+dc
                    if (nr,nc) in eights and (nr,nc) not in visited_8:
                        q.append((nr,nc))
        for cell in struct:
            structures[cell] = struct

    # Find chains via ray-based detection
    chains = []
    seen_chains = set()

    for r, c in eights:
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            while 0 <= nr < H and 0 <= nc < W:
                v = int(grid[nr, nc])
                if v == 8: break
                if v != 0:
                    b_pos = (nr, nc)
                    b_color = v
                    a_r, a_c = nr + dr, nc + dc
                    if 0 <= a_r < H and 0 <= a_c < W:
                        a_v = int(grid[a_r, a_c])
                        if a_v != 0 and a_v != 8 and a_v != b_color:
                            key = (a_r, a_c, nr, nc)
                            if key not in seen_chains:
                                seen_chains.add(key)
                                direction = (-dr, -dc)
                                chains.append({
                                    'a_pos': (a_r, a_c),
                                    'a_color': a_v,
                                    'b_pos': b_pos,
                                    'b_color': b_color,
                                    'direction': direction,
                                    'eight_cell': (r, c),
                                })
                    break
                nr += dr; nc += dc

    # Collect legend cells
    legend_cells = set()
    for ch in chains:
        legend_cells.add(ch['a_pos'])
        legend_cells.add(ch['b_pos'])

    # For each chain, compute the stamp offsets
    color_transforms = {}

    for ch in chains:
        a_color = ch['a_color']
        b_color = ch['b_color']
        direction = ch['direction']
        b_pos = ch['b_pos']
        eight_cell = ch['eight_cell']

        ref = (b_pos[0] + direction[0], b_pos[1] + direction[1])
        struct = structures.get(eight_cell, {eight_cell})
        offsets = [(r - ref[0], c - ref[1]) for r, c in struct]

        color_transforms[a_color] = (b_color, offsets)

    # Apply transforms to pattern cells
    for r in range(H):
        for c in range(W):
            v = int(grid[r,c])
            if v != 0 and v != 8 and (r,c) not in legend_cells:
                if v in color_transforms:
